function(config){
  const cfg=config&&typeof config==='object'?config:{};
  const pageUrl=(typeof location!=='undefined'&&location.href)?location.href:(cfg.page&&cfg.page.url)||'';
  const q=String(cfg.query||cfg.searchQuery||'').trim().toLowerCase();
  const minItems=Math.max(1,Math.min(50,Number(cfg.minItems||1)));
  const requireFields=Array.isArray(cfg.requireFields)?cfg.requireFields:[];
  const target=cfg.target&&typeof cfg.target==='object'?cfg.target:{};

  const normSpace=s=>String(s||'').replace(/\s+/g,' ').trim();
  const textOf=el=>{ if(!el) return ''; const t=normSpace(el.innerText||el.textContent||''); return t; };
  const toAbs=u=>{ u=String(u||'').trim(); if(!u) return ''; try{ return new URL(u,pageUrl).href; }catch(e){ return ''; } };
  const isBadText=t=>{ t=(t||'').toLowerCase(); return /\b(login|sign\s?in|sign\s?up|register|privacy|terms|cookie|help|feedback|about|advert|sponsor)\b/.test(t)||/登录|注册|隐私|条款|帮助|反馈|广告|推荐/.test(t); };
  const isInBadRegion=el=>{ for(let n=el;n&&n.nodeType===1;n=n.parentElement){ const tag=(n.tagName||'').toLowerCase(); if(['header','nav','footer','aside'].includes(tag)) return true; const id=(n.id||'').toLowerCase(); const cls=(n.className||'').toString().toLowerCase(); if(/\b(sidebar|sidenav|nav|footer|header|masthead|menu|breadcrumb|cookie|consent|modal|dialog|login|signup|register|help|policy|privacy|terms|advert|ads|sponsor|recommend|related)\b/.test(id+' '+cls)) return true; }
    return false;
  };

  const pickItems=(items,pick)=>{
    if(pick===undefined||pick===null||pick==='') return items;
    if(typeof pick==='number'&&isFinite(pick)){
      if(pick===-1) return items.length?[items[items.length-1]]:[];
      const idx=Math.max(1,Math.floor(pick))-1;
      return items[idx]?[items[idx]]:[];
    }
    if(typeof pick==='string'){
      const s=pick.toLowerCase();
      for(const it of items){ const t=(it&&it.__text||'').toLowerCase(); if(t.includes(s)) return [it]; }
      return [];
    }
    return items;
  };

  const extractFromItemEl=el=>{
    const a=el.querySelector('a[href]');
    let url=a?toAbs(a.getAttribute('href')):'';
    let title='';
    if(a) title=normSpace(a.getAttribute('title')||textOf(a));
    if(!title){
      const h=el.querySelector('h1,h2,h3,h4,strong,b,[role="heading"]');
      title=normSpace(textOf(h)||'');
    }
    if(!title) title=normSpace(textOf(el).split('\n')[0]||'');
    let summary='';
    const ps=Array.from(el.querySelectorAll('p,div,span')).filter(x=>x&&x!==a);
    for(const n of ps){
      const t=normSpace(textOf(n));
      if(!t||t===title) continue;
      if(t.length>=6){ summary=t; break; }
    }
    if(!summary){
      const t=normSpace(textOf(el));
      summary=t&&t!==title?t.slice(0,240):'';
    }
    if(isBadText(title+' '+summary)) return null;
    return {url:url||'',title:title||'',summary:summary||''};
  };

  const findNextCursor=(root)=>{
    const scope=root||document;
    const links=Array.from(scope.querySelectorAll('a[href]')).filter(a=>!isInBadRegion(a));
    const cur=pageUrl||'';
    const cand=[];
    for(const a of links){
      const t=normSpace((a.getAttribute('aria-label')||'')+' '+textOf(a)).toLowerCase();
      if(!t) continue;
      if(/\b(next|older|more)\b/.test(t)||/下一页|下页|更多|下一章|后页/.test(t)||/\bpage\s*\d+\b/.test(t)){
        const href=toAbs(a.getAttribute('href'));
        if(href&&href!==cur) cand.push({href,score:(/next|下一页/.test(t)?3:1)+(a.closest('[aria-label*="pagination"],[class*="pag"],[id*="pag"],nav')?1:0)});
      }
    }
    cand.sort((x,y)=>y.score-x.score);
    return cand[0]?cand[0].href:null;
  };

  const resolveTargetRoot=()=>{
    let root=null;
    const by=String(target.by||'').toLowerCase();
    const sel=String(target.selector||'').trim();
    const query=String(target.query||'').trim();
    if(sel){ try{ root=document.querySelector(sel); }catch(e){} }
    if(!root&&query){ try{ root=document.querySelector(query); }catch(e){} }
    if(!root&&by==='query'&&query){ try{ root=document.querySelector(query); }catch(e){} }
    if(!root&&by==='selector'&&sel){ try{ root=document.querySelector(sel); }catch(e){} }
    return root;
  };

  const scoreContainer=(c)=>{
    if(!c||isInBadRegion(c)) return -1;
    const items=Array.from(c.children||[]).filter(x=>x&&x.nodeType===1);
    if(items.length<2) return -1;
    const tag=(c.tagName||'').toLowerCase();
    let s=0;
    if(tag==='ul'||tag==='ol') s+=2;
    const cls=(c.className||'').toString().toLowerCase();
    const id=(c.id||'').toLowerCase();
    if(/\b(result|results|list|items|feed|content|main)\b/.test(cls+' '+id)) s+=2;
    const sameClass=items.filter(it=>it.className&&it.className===items[0].className).length;
    s+=Math.min(6,items.length);
    s+=sameClass>=Math.max(2,Math.floor(items.length*0.6))?2:0;
    const linkCount=items.reduce((acc,it)=>acc+(it.querySelector('a[href]')?1:0),0);
    s+=linkCount>=Math.max(1,Math.floor(items.length*0.4))?2:0;
    if(q){
      const t=textOf(c).toLowerCase();
      if(t.includes(q)) s+=1;
    }
    return s;
  };

  const collectItemsFromContainer=(container)=>{
    if(!container) return [];
    let itemEls=[];
    const tag=(container.tagName||'').toLowerCase();
    if(tag==='ul'||tag==='ol') itemEls=Array.from(container.querySelectorAll(':scope > li'));
    if(!itemEls.length) itemEls=Array.from(container.children||[]).filter(n=>n&&n.nodeType===1);
    if(itemEls.length>80) itemEls=itemEls.slice(0,80);
    const out=[];
    for(const el of itemEls){
      if(!el||isInBadRegion(el)) continue;
      const t=textOf(el);
      const rec=extractFromItemEl(el);
      if(!rec) continue;
      const obj={url:rec.url,title:rec.title,summary:rec.summary,__text:t};
      out.push(obj);
      if(out.length>=50) break;
    }
    return out;
  };

  const applyOutputRules=(items)=>{
    let arr=items.map(it=>({url:String(it.url||''),title:String(it.title||''),summary:String(it.summary||''),__text:it.__text||''}));
    if(q) arr=arr.filter(it=>(it.title+' '+it.summary+' '+it.url).toLowerCase().includes(q));
    if(cfg.filter&&typeof cfg.filter==='object'){
      const f=cfg.filter;
      if(typeof f.include==='string'&&f.include.trim()){
        const inc=f.include.toLowerCase();
        arr=arr.filter(it=>(it.title+' '+it.summary+' '+it.url).toLowerCase().includes(inc));
      }
      if(typeof f.exclude==='string'&&f.exclude.trim()){
        const exc=f.exclude.toLowerCase();
        arr=arr.filter(it=>!(it.title+' '+it.summary+' '+it.url).toLowerCase().includes(exc));
      }
    }
    if(cfg.sort&&typeof cfg.sort==='object'){
      const s=cfg.sort;
      const by=String(s.by||'').toLowerCase();
      const dir=String(s.dir||'asc').toLowerCase()==='desc'?-1:1;
      if(by==='title'||by==='url'||by==='summary') arr.sort((a,b)=>a[by].localeCompare(b[by])*dir);
    }
    arr=pickItems(arr,target.pick);
    arr=arr.map(it=>({url:it.url||'',title:it.title||'',summary:it.summary||''}));
    if(requireFields.length){
      arr=arr.filter(it=>requireFields.every(k=>typeof it[k]==='string'&&it[k].trim()!==''));
    }
    return arr.slice(0,50);
  };

  const attempt=(root)=>{
    const scope=root||document;
    const containers=[];
    const main=scope.querySelector('main')||scope.querySelector('[role="main"]')||scope.querySelector('#content')||scope.querySelector('.content')||scope.body||document.body;
    const base=main||scope;
    const cand=Array.from(base.querySelectorAll('ul,ol,[role="list"],section,div'));
    for(const c of cand){
      if(!c||isInBadRegion(c)) continue;
      const sc=scoreContainer(c);
      if(sc>=4) containers.push({c,sc});
    }
    containers.sort((a,b)=>b.sc-a.sc);
    const top=containers.slice(0,6);
    for(const {c} of top){
      const items=collectItemsFromContainer(c);
      const out=applyOutputRules(items);
      if(out.length>=Math.min(minItems,3)) return {items:out,root:c};
    }
    return {items:[],root:base};
  };

  const targetRoot=resolveTargetRoot();
  let r=attempt(targetRoot);
  if(r.items.length<minItems){
    const fallbackRoot=(document.querySelector('main')||document.querySelector('[role="main"]')||document.body);
    r=attempt(fallbackRoot);
  }

  const nextCursor=findNextCursor(r.root||targetRoot||document);
  return {action:'list',items:r.items,nextCursor:nextCursor,pageUrl:pageUrl||''};
}

function(config){
  function txt(el){return (el&&el.textContent?el.textContent:" ").replace(/\s+/g," ").trim();}
  function attr(el,n){return el&&el.getAttribute?((el.getAttribute(n)||"").trim()):"";}
  function pickRoot(){
    var t=config&&config.target;
    if(t){
      if(typeof t==="string"){
        var r=document.querySelector(t);
        if(r) return r;
      }else if(t&&t.nodeType===1){
        return t;
      }else if(t&&typeof t==="object"){
        var sel=t.selector||t.query||t.css;
        if(sel&&typeof sel==="string"){
          var r2=document.querySelector(sel);
          if(r2) return r2;
        }
      }
    }
    return document.querySelector('article, main, [role="main"], #content, .content, .post, .article') || document.body;
  }
  function scorePanel(root){
    var panels=Array.from(root.querySelectorAll('#reaction-panel, .reaction, .reactions, .toolbar, .tool-bar, [aria-label*="点赞"], [aria-label*="评论"], [data-testid*="favorite"], [data-testid*="like"], [data-testid*="comment"], [data-testid*="share"], [class*="reaction"], [class*="toolbar"]'));
    var best=null,bestScore=-1;
    for(var i=0;i<panels.length;i++){
      var p=panels[i];
      var t=txt(p);
      if(!t) continue;
      var s=0;
      if(/点赞|like/i.test(t)) s+=3;
      if(/评论|comment/i.test(t)) s+=3;
      if(/转发|分享|share|repost/i.test(t)) s+=2;
      if(/收藏|favorite|bookmark/i.test(t)) s+=2;
      if(/浏览|阅读|view/i.test(t)) s+=2;
      if(p.id==="reaction-panel") s+=4;
      if(s>bestScore){bestScore=s;best=p;}
    }
    return best||root;
  }
  function parseCounts(root){
    var data={likes:"",comments:"",shares:"",favorites:"",views:"",upvotes:"",downvotes:"",pageUrl:(location&&location.href)||""};
    var panel=scorePanel(root);
    var nodes=Array.from(panel.querySelectorAll('button, a, span, div, li'));
    if(nodes.length<3) nodes=Array.from(root.querySelectorAll('#reaction-panel button, #reaction-panel span, .toolbar button, .toolbar span, [aria-label], [title], [data-testid]'));

    function consider(label,val){
      if(!val) return;
      if(label==="likes" && !data.likes) data.likes=val;
      else if(label==="comments" && !data.comments) data.comments=val;
      else if(label==="shares" && !data.shares) data.shares=val;
      else if(label==="favorites" && !data.favorites) data.favorites=val;
      else if(label==="views" && !data.views) data.views=val;
      else if(label==="upvotes" && !data.upvotes) data.upvotes=val;
      else if(label==="downvotes" && !data.downvotes) data.downvotes=val;
    }

    function extractVal(s){
      s=(s||"").replace(/\s+/g," ").trim();
      var m=s.match(/(?:^|\b)(\d+(?:[\.,]\d+)?\s*(?:k|K|m|M|万|亿)?)(?=\b|$)/);
      if(m) return m[1].replace(/\s+/g,"");
      var m2=s.match(/(\d+(?:[\.,]\d+)?\s*(?:k|K|m|M|万|亿))/);
      return m2?m2[1].replace(/\s+/g,""):"";
    }

    for(var i=0;i<nodes.length;i++){
      var el=nodes[i];
      var s=[attr(el,"aria-label"),attr(el,"title"),attr(el,"data-label"),txt(el)].filter(Boolean).join(" ");
      if(!s) continue;
      var v=extractVal(s);
      if(!v) continue;
      if(/点赞|喜欢|like/i.test(s)) consider("likes",v);
      if(/评论|comment/i.test(s)) consider("comments",v);
      if(/转发|分享|share|repost/i.test(s)) consider("shares",v);
      if(/收藏|favorite|bookmark/i.test(s)) consider("favorites",v);
      if(/浏览|阅读|view/i.test(s)) consider("views",v);
      if(/顶|upvote|赞同/i.test(s)) consider("upvotes",v);
      if(/踩|downvote|反对/i.test(s)) consider("downvotes",v);
    }

    if(!data.likes||!data.comments||!data.shares||!data.favorites||!data.views){
      var all=txt(panel);
      var parts=all.split(/\s*[|·•]\s*|\s{2,}/).filter(Boolean);
      for(var j=0;j<parts.length;j++){
        var p=parts[j];
        var vv=extractVal(p);
        if(!vv) continue;
        if(/点赞|喜欢|like/i.test(p)) consider("likes",vv);
        else if(/评论|comment/i.test(p)) consider("comments",vv);
        else if(/转发|分享|share|repost/i.test(p)) consider("shares",vv);
        else if(/收藏|favorite|bookmark/i.test(p)) consider("favorites",vv);
        else if(/浏览|阅读|view/i.test(p)) consider("views",vv);
      }
    }

    return data;
  }

  var root=pickRoot();
  var data=parseCounts(root);
  var filled=(data.likes||data.comments||data.shares||data.favorites||data.views||data.upvotes||data.downvotes);
  if(!filled){
    var root2=document.querySelector('#reaction-panel, article, main, [role="main"], body')||document.body;
    data=parseCounts(root2);
  }
  return {action:"reactions",data:data};
}

function(config){
  config = config || {};
  var limit = typeof config.limit === 'number' && isFinite(config.limit) ? Math.max(0, Math.floor(config.limit)) : 50;

  function normRole(raw){
    raw = (raw || '').toLowerCase().trim();
    if (raw === 'user' || raw === 'assistant' || raw === 'system' || raw === 'tool') return raw;
    return 'unknown';
  }

  function textOf(el){
    if (!el) return '';
    var t = '';
    var tEl = el.querySelector('.text,[data-role="text"],[data-message-role-text]');
    if (tEl) t = (tEl.innerText || tEl.textContent || '');
    else t = (el.innerText || el.textContent || '');
    t = (t || '').replace(/\r\n/g,'\n').replace(/\u00a0/g,' ').trim();
    return t;
  }

  function metaFrom(el){
    var time = '';
    var status = '';
    var meta = el.querySelector('.meta,[data-role="meta"],[data-message-meta]');
    if (meta){
      var spans = Array.from(meta.querySelectorAll('span, time'));
      var parts = spans.map(function(s){ return (s.innerText || s.textContent || '').trim(); }).filter(Boolean);
      if (parts.length >= 2) time = parts[1] || '';
      if (parts.length >= 3) status = parts[2] || '';
      var timeEl = meta.querySelector('time');
      if (timeEl){
        var dt = (timeEl.getAttribute('datetime') || '').trim();
        if (!time && dt) time = dt;
      }
    } else {
      var timeEl2 = el.querySelector('time');
      if (timeEl2){
        time = ((timeEl2.getAttribute('datetime') || timeEl2.innerText || timeEl2.textContent || '') + '').trim();
      }
    }
    return {time: time, status: status};
  }

  function stableId(el, role, index, text){
    var id = (el.getAttribute('data-message-id') || el.id || el.getAttribute('data-id') || '').trim();
    if (id) return id;
    var prefix = (text || '').slice(0, 32);
    return role + ':' + index + ':' + prefix;
  }

  function extract(root){
    var nodes = Array.from(root.querySelectorAll('article[data-role="message"], [data-role="message"], [data-message-role], [role="listitem"]'));
    nodes = nodes.filter(function(n){
      if (!n || n.nodeType !== 1) return false;
      if (n.closest('aside, nav, header, footer')) return false;
      if (n.closest('[data-role="session-list"], .sidebar')) return false;
      return true;
    });

    var items = [];
    for (var i=0;i<nodes.length;i++){
      var el = nodes[i];
      var rawRole = (el.getAttribute('data-message-role') || (el.dataset && el.dataset.messageRole) || (el.dataset && el.dataset.role) || '').trim();
      if (!rawRole){
        var cls = (el.className || '').toLowerCase();
        if (cls.indexOf('assistant') >= 0) rawRole = 'assistant';
        else if (cls.indexOf('user') >= 0) rawRole = 'user';
        else if (cls.indexOf('system') >= 0) rawRole = 'system';
        else if (cls.indexOf('tool') >= 0) rawRole = 'tool';
      }
      var role = normRole(rawRole);
      var text = textOf(el);
      if (!text) continue;
      var meta = metaFrom(el);
      var id = stableId(el, role, items.length, text);
      items.push({
        id: String(id),
        role: String(role),
        text: String(text),
        time: String(meta.time || ''),
        status: String(meta.status || ''),
        index: items.length
      });
    }
    return items;
  }

  var root = document.querySelector('[data-role="chat-log"], main [data-role="chat-log"], .chat, #chat-log') || document.querySelector('main') || document.body || document.documentElement;
  var items = extract(root);

  if (!items.length){
    var alt = document.querySelector('main') || document.body || document.documentElement;
    items = extract(alt);
  }

  if (limit && items.length > limit) items = items.slice(items.length - limit);
  for (var j=0;j<items.length;j++) items[j].index = j;

  var cursor = items.length ? (items[items.length-1].id || '') : '';
  return {action:'getMessages',items:items,cursor:String(cursor||'')};
}
